sp_widget.client_script:
api.controller = function($scope, $rootScope) {
    /* widget controller */
    var c = this;
    c.currentItem = null;
    c.currentSection = 0;

	$scope.server.update().then(function(resp) {
		if (resp.sectionList[0].itemList.length > 0) {
			//$scope.showProduct(true, 0) /* MSPI-2236 by Rogério */
			$rootScope.$broadcast('upgradeAvailable', true);
		}
	})

    $scope.showProduct = function(upgradeAvailable, index) {
        var selectedItem = upgradeAvailable ? $scope.data.sectionList[0].itemList[index] : $scope.data.sectionList[1].itemList[index];
        c.currentItem = index;
        c.currentSection = upgradeAvailable ? 0 : 1;
        $scope.setSubTitleToTrackerOderWidget();
        $rootScope.$broadcast('addNewBreadcrumb', {
            sys_id: '',
            label: selectedItem.name,
            url: ""
        });
        $rootScope.$broadcast('SelectTrackOrder', selectedItem);
    };

    $scope.setSubTitleToTrackerOderWidget = function() {
        var subTitle = '${Select the item you wish to see details and/or modify.}';
        var subTitle2 = '${Modifications not allowed for Reseller accounts.}';
        if (!$scope.data.sectionList[0].itemList.length > 0) {
            subTitle = '${Select the item you wish to see more details.}';
        }
        if (subTitle == '${Select the item you wish to see details and/or modify.}') {
            $rootScope.$broadcast('setSubTitle', subTitle);
            $rootScope.$broadcast('setSubTitle2', subTitle2);
        } else {
            $rootScope.$broadcast('setSubTitle', subTitle);
        }
    };

    identifyPageTracking(c.data.pageTitle, 'Asset Inventory', c.data.trackingEnabled, c.data.categoriesTrackingEnabled);

    $scope.track = function(event, properties) {
        properties.category = c.data.pageTitle;
        createTracking(event, properties, c.data.trackingEnabled, c.data.categoriesTrackingEnabled);
    };

};

sp_widget.css:
.sidebar {
  height: 100vh;
	box-shadow: 0.3rem 0 0.4rem 0.1rem rgba(42, 48, 60, 0.1);
  border-left: none;
  border-top-right-radius: var(--eq-border-radius-regular);
}

.item-list {
  overflow-y: auto;
  height: calc(100vh - #{$navbar-height__header} - #{$navbar-height__menu} - 3px - 10px - 42px - 40px)
}
.item {
  border-left: solid 4px transparent;
  color: var(--eq-color-blue-900);
  font-family: var(--eq-typography-body-font-family);
  font-weight: var(--eq-typography-body-font-weight);
  font-size: var(--eq-typography-body-font-size);
  letter-spacing: var(--eq-typography-body-letter-spacing);
  word-spacing: var(--eq-typography-body-paragraph-spacing);
}
.item:hover {
  background-color: var(--eq-color-blue-50);
  color: var(--eq-color-primary-active);
}
.item.active {
  color: var(--eq-color-primary-base);
  border-left-color: var(--eq-color-primary-base);
  font-family: var(--eq-typography-body-bold-font-family);
  font-weight: var(--eq-typography-body-bold-font-weight);
  font-size: var(--eq-typography-body-bold-font-size);
  letter-spacing: var(--eq-typography-body-bold-letter-spacing);
  word-spacing: var(--eq-typography-body-bold-paragraph-spacing);
}

sp_widget.script:
(function() {

	data.trackingEnabled = gs.getProperty('EQIX_ANALYTICS_SEGMENT_ENABLED'); //Tracking to analytics
	data.categoriesTrackingEnabled = gs.getProperty('EQIX_ANALYTICS_CATEGORIES_ENABLED'); //This is to validate if it is Enabled
	data.pageTitle = 'Asset Inventory';

	data.environment = gs.getProperty('glide.servlet.uri').includes("https://equinixcsm.service-now.com/") ? false : true;
	//
	data.sectionList = [
		{
			name: gs.getMessage(''),
			itemList: []
		},
		{
			name: gs.getMessage('All-Assets'),
			itemList: []
		}
	];
	data.load = false;
	var servCount = '';
	var servName = '';
	var macdAvailable = false;
	var _ = new EQIX_Lodash();

	new EQIX_Reseller_Account().initialize();
	var customerPermission = new EQIX_Customer_Permissions();
	var account = customerPermission.getActiveAccountSysId();
	data.productsPathIMG = gs.getProperty('EQIX.MSP.Sidebar.IconsNames');
	var productIcons = JSON.parse(gs.getProperty('EQIX.MSP.Sidebar.IconsNames'));
	var grAccount = new GlideRecord("customer_account");

	grAccount.get(account);
	var operatingUnit = grAccount.getValue('u_operating_unit');

	var grCoreCountry = new GlideRecord("core_country");
	grCoreCountry.addQuery("iso3166_2", operatingUnit);
	grCoreCountry.query();

	var country_sys_id = '';
	if(grCoreCountry.next()){
		country_sys_id = grCoreCountry.getValue("sys_id");
	}

	var query = "account.sys_id="+account+"^active=true^u_siebel_asset_status=Active^u_product.u_part_numberISNOTEMPTY";
	if (input) {
		data.itemlist = [];
		generateListFilter(true);
		generateListFilter(false);
	}

	function generateListFilter(macdAvailable) {
		var countID = 0;
		var isReseller = new EQIX_Reseller_Account().verifyIfResellerAccount();
		var isResellerSubAccount = new EQIX_Reseller_Account().verifyIfResellerSubAccount();

		var agg = new GlideAggregate('sn_customerservice_contract_item');
		agg.addEncodedQuery("^u_product.cmdb_model_categoryLIKE"+gs.getProperty('Model_Category_Bundle')+"^ORu_product.cmdb_model_categoryISEMPTY");

		if(macdAvailable && (!isReseller && !isResellerSubAccount)) {
			agg.addEncodedQuery(query + "^u_product.u_macd_self_service=" + macdAvailable + "^u_product.u_macd_operating_unitLIKE"+country_sys_id);
		} else if(!isReseller && !isResellerSubAccount) {
			agg.addEncodedQuery(query + "^u_product.u_part_number!=MSPACKAGE.PROD^u_product.u_macd_self_service=" + macdAvailable );
		} else {
			agg.addEncodedQuery(query + "^u_product.u_part_number!=MSPACKAGE.PROD");
		}

		agg.addAggregate('COUNT', 'u_product');
		agg.orderBy('u_product');
		agg.query();

		while (agg.next()) {
			var item = {};
			servCount = agg.getAggregate('COUNT', 'u_product');
			servName = agg.getDisplayValue('u_product');
			var product_sysID = agg.getValue('u_product');
			item.contractPOF_sys_id = valuesPof(product_sysID);
			item.addToList = checkIfPOFHasPOEMACDLikeTrue(agg.getValue('u_product'));
			item.name = servName;
			item.count = servCount;
			item.id = countID;
			item.macdAvailable = macdAvailable;
			item.partNumber = getPartNumber(product_sysID);
			item.icon = 'managed_backup.png';
			item.name = servName;
			var uiMessage = "PN_"+ servName;
			item.tName = translateProductName(uiMessage,servName);

			var matchedIcons = productIcons.filter(function(element){
				return element.partNumber == item.partNumber
			})

			if(matchedIcons.length > 0) item.icon = matchedIcons[0].img;

			if (macdAvailable && !isReseller && data.environment == true) {
				data.sectionList[0].itemList.push(item);
			} else {
				if (item.addToList && !hasItAlreadyBeenAdded(item.name)) {
					data.sectionList[1].itemList.push(item);	
				}
			}
			countID++;
		}
		checkWhetherToShowTheContent();
	}

	function checkWhetherToShowTheContent() {
		if(data.sectionList[0].itemList.length > 0 || data.sectionList[1].itemList.length > 0) {
			data.showContent = true;
		} else {
			data.showContent = false;
		}
	}

	function hasItAlreadyBeenAdded(_name) {
		var checkItem = _.find(data.sectionList[1].itemList, function(item) { return item.name == _name; });
		var response = checkItem == undefined ? false : true;
		return response;
	}

	function checkIfPOFHasPOEMACDLikeTrue(_productPOFSySID) {
		var response = false;
		var grSCCI = new GlideAggregate('sn_customerservice_contract_item');
		grSCCI.addEncodedQuery("account.sys_id=" + account + "^u_product.cmdb_model_categoryLIKE" + gs.getProperty('Model Category POE') + "^u_product.u_macd_self_service=true" + "^parent.u_product.sys_id=" + _productPOFSySID);
		grSCCI.addAggregate("COUNT");
		grSCCI.query();
		grSCCI.next();
		response = checkTotalCount(grSCCI)
		return response
	}

	function checkTotalCount(_grCM2MC) {
		try {
			return Number(_grCM2MC.getAggregate("COUNT")) > 0 ? true : false;
		} catch (err) {
			return false;
		}
	}

	data.load = false;

	function translateProductName(PN_product, productName){
		var uiMsg = gs.getMessage(PN_product);
		if(uiMsg.includes("PN_")){
			return productName;
		}
		else{
			return uiMsg;
		}
	}

	function valuesPof(product_sysID){
		var grPofCountract  = new GlideRecord('sn_customerservice_contract_item');
		grPofCountract.addEncodedQuery(query+'^u_product='+product_sysID);
		grPofCountract.orderBy('u_product');
		grPofCountract.query();
		var list = []
		while(grPofCountract.next()){
			list.push(grPofCountract.getValue("sys_id"));
		}
		return list;
	}

	function getPartNumber(productSysID) {
		var response = "BAK00001.PROD";
		var grUMS = new GlideRecord('u_managed_service');
		grUMS.addEncodedQuery("sys_id=" + productSysID);
		grUMS.query();
		if (grUMS.next()) response = grUMS.getValue('u_part_number');
		return response;
	}  

})();
